import {InputHTMLAttributes, useEffect, useState} from "react";
import {isNumber} from "lodash";

export default function FriendlyNumberInput({value: val, onChange, min: minVal, max: maxVal, step, ...rest}: {
    value: number, onChange: (newVal: number) => void
}  & Omit<InputHTMLAttributes<HTMLInputElement>, 'value' | 'onChange' | 'onBlur' | 'type'>) {
    const [liveState, setLiveState] = useState(val.toString())
    useEffect(() => {
        setLiveState(val.toString())
    }, [val]);
    const realStep = (!step ? 1 : (isNumber(step) ? step : parseFloat(step) || 1))
    const parseFunc =  realStep < 1 ? parseFloat : parseInt

    return <input type="number" value={liveState} min={minVal} max={maxVal}
                  step={step} {...rest}
                  onChange={(e) => {
                      setLiveState(e.currentTarget.value)
                      // If arrows used, update immediately since a blur won't happen
                      if(e.currentTarget != document.activeElement) {
                          onChange(parseFunc(e.currentTarget.value))
                      }
                  }}
                  onBlur={(e) => {
                      let newValue = parseFunc(e.currentTarget.value)
                      if(minVal != undefined && newValue < (isNumber(minVal) ? minVal : parseFloat(minVal))) {
                          newValue = isNumber(minVal) ? minVal : parseFloat(minVal)
                      }
                      if(maxVal != undefined && newValue > (isNumber(maxVal) ? maxVal : parseFloat(maxVal))) {
                          newValue = isNumber(maxVal) ? maxVal : parseFloat(maxVal)
                      }
                      if(isNaN(newValue)) {
                          // if invalid on blur restore to previous value
                          setLiveState(val.toString())
                      } else {
                          setLiveState(newValue.toString())
                          onChange(newValue)
                      }
                  }} style={{width: "5em"}} />
}