import LocalErrorBoundary from "../../LocalErrorBoundary";
import MatchSchedule, {MatchCountData, ScheduleBlock} from "./MatchSchedule";
import { Temporal } from 'temporal-polyfill';
import { createRoot } from "react-dom/client";

declare global {
    interface Window {
        eventCode: string,
        startDate: string,
        endDate: string,
        matchCountData: MatchCountData,
        currentSchedule: ScheduleBlock[],
        allowCustomSchedules: boolean,
        matchPhase: 'PRACTICE' | 'QUALS'
    }
}

const container = document.getElementById('reactContainer');
if(!container) {
    console.error("Mount point for container not found")
} else {
  const root = createRoot(container);
  root.render(<LocalErrorBoundary>
        <MatchSchedule eventCode={window.eventCode}
                       matchCountData={window.matchCountData}
                       initialSchedule={window.currentSchedule.map(s => {
                           const newBlock = {
                               ...s,
                               start: Temporal.PlainDateTime.from(s.start),
                               end: Temporal.PlainDateTime.from(s.end)
                           }
                           if (newBlock.type == "MATCH") {
                               newBlock.cycleTime = Temporal.Duration.from(newBlock.cycleTime);
                           }
                           return newBlock
                       })}
                       allowCustomSchedules={window.allowCustomSchedules}
                       startDate={Temporal.PlainDate.from(window.startDate)}
                       endDate={Temporal.PlainDate.from(window.endDate)}
                       phase={window.matchPhase} />
    </LocalErrorBoundary>);
}