import {FocusEvent, InputHTMLAttributes, useEffect, useId, useReducer, useRef, useState} from "react";
import {msgid, ngettext, t} from "ftc-common/i18n";
import {Alert, Button, Form, OverlayTrigger, ProgressBar, Tooltip} from "react-bootstrap";
import {PermissiveURLSearchParams, usePersistentWebsocket} from "ftc-common/utils";
import {Temporal} from 'temporal-polyfill'
import {MatchMakerStatus, MatchMakerUpdate, ScheduleData} from "../../javaTypes";
import { confirmDialog, messageDialog } from "first-common/dialogs";
import {ChangeEvent, useCallback} from "react";
import FriendlyNumberInput from "first-common/FriendlyNumberInput";

export interface MatchCountData {
    teamCount: number
    perTeam: number
    minPerTeam: number
    maxPerTeam: number
}

export type ScheduleBlock = MatchBlock | BreakBlock
interface MatchBlock {
    roundInfo?: string
    readOnly?: boolean
    type: "MATCH"
    cycleTime: Temporal.Duration
    start: Temporal.PlainDateTime
    end: Temporal.PlainDateTime
}

interface BreakBlock {
    type: "BREAK"
    label: string
    start: Temporal.PlainDateTime
    end: Temporal.PlainDateTime,
    visible: boolean
}

const timeFormatOpts = [document.documentElement.lang, { hour: "numeric", minute: "numeric" }] as const;
function matchesPerBlock(block: MatchBlock) {
    return Math.max(0, Math.floor(block.start.until(block.end).total({ unit: 'second' }) / block.cycleTime.total({ unit: 'second' })));
}

function EditMatchBlock({date, block, updateBlock, overlaps, minCycle}: {date: Temporal.PlainDate, block: MatchBlock, updateBlock: (block?: MatchBlock) => void, overlaps: boolean, minCycle: number}) {
    const matchCount = matchesPerBlock(block);
    const extraTime = block.start.until(block.end).subtract({ seconds: block.cycleTime.total({ unit: 'second' }) * matchCount }).total({ unit: 'minute' });
    const id = useId();
    const cycleTime = block.cycleTime.total({ unit: 'minute' })

    return <div className={"border border-dark m-2 p-2"}>
        <h4 className={"form-inline"}>{block.start.toLocaleString(...timeFormatOpts)} - {block.end.toLocaleString(...timeFormatOpts)}: {block.readOnly ? matchCount :
            <FriendlyNumberInput
            className="ml-2 mr-2"
            value={matchCount}
            min={0}
            style={{width: "5em"}}
            onChange={(val) => {
                let newEnd = block.start.add(Temporal.Duration.from({seconds: val * block.cycleTime.total({ unit: 'second' })}));
                if(block.cycleTime.total({ unit: 'minute' }) >= 5) {
                    newEnd = newEnd.round({smallestUnit: "minutes", roundingMode: "expand", roundingIncrement: 5});
                }
                updateBlock({...block,
                    end: newEnd
                })
            }}
        />}{' '}{ngettext(msgid`Match`, msgid`Matches`, matchCount)} {block.readOnly ? t` already played` : null}
            {overlaps ? <OverlayTrigger overlay={<Tooltip id={`${id}-overlap`}>
            {t`This block overlaps with another block.`}
        </Tooltip>}>
            <i className="fas fa-exclamation-triangle"></i>
        </OverlayTrigger> : null}</h4>
        <h5>{block.start.until(block.end).total({ unit: "minutes"})} minutes {extraTime > 0 ? ngettext(msgid`(Last match ends ${extraTime} minute before end of block)`, `(Last match ends ${extraTime} minutes before end of block)`, extraTime) : null}</h5>
        {block.readOnly ? <div>{t`Cycle Time: ${cycleTime}`}</div> : <Form inline>
            <Form.Label htmlFor={`${id}-start`} className="mr-2">
                {t`Start`}
            </Form.Label>
            <Form.Control
                className="mr-2"
                id={`${id}-start`}
                type="time"
                value={block.start.toPlainTime().toString({ smallestUnit: 'minute' })}
                onChange={(e) => {
                    const newStart = date.toPlainDateTime(Temporal.PlainTime.from(e.currentTarget.value));
                    updateBlock({...block,
                        start: newStart,
                        end: newStart.add(block.start.until(block.end))
                    })
                }}
            />
            <Form.Label htmlFor={`${id}-end`} className="mr-2">
                {t`End`}
            </Form.Label>
            <Form.Control
                className="mr-2"
                id={`${id}-end`}
                type="time"
                value={block.end.toPlainTime().toString({ smallestUnit: 'minute' })}
                onChange={(e: FocusEvent<HTMLInputElement>) => updateBlock({...block, end: date.toPlainDateTime(Temporal.PlainTime.from(e.currentTarget.value))})}
            />
            <Form.Label htmlFor={`${id}-cycle`} className="mr-2">
                {t`Cycle Time`}
            </Form.Label>
            <FriendlyNumberInput
                className="mr-2"
                id={`${id}-cycle`}
                min={minCycle}
                step={0.5}
                value={cycleTime}
                onChange={(val) => updateBlock({...block, cycleTime: Temporal.Duration.from({ seconds: val * 60 })})}
            />
            <div className={"flex-grow-1"} />
            <Button variant={"secondary"} size={"sm"} onClick={() => updateBlock(undefined)}>{t`Remove`}</Button>
        </Form>}
        <small>{block.roundInfo}</small>
    </div>
}

function EditBreakBlock({block, updateBlock}: { updateBlock: (block?: BreakBlock) => void, block: BreakBlock }) {
    const id = useId();

    return <div className={"border border-dark m-2 p-2"}>
        <h4>{block.start.toLocaleString(...timeFormatOpts)} - {block.end.toLocaleString(...timeFormatOpts)}: Break</h4>
        <h5>{block.start.until(block.end).total({unit: "minutes"})} minutes</h5>
        <Form inline>
            <Form.Label htmlFor={`${id}-label`} className="mr-2">
                {t`Label`}
            </Form.Label>
            <Form.Control
                className="mr-2"
                id={`${id}-label`}
                value={block.label}
                style={{width: "15em"}}
                onChange={(e) => updateBlock({...block, label: e.currentTarget.value, visible: block.label.length == 0 ? true : (e.currentTarget.value.length == 0 ? false : block.visible)})}
            />
            <Form.Label htmlFor={`${id}-visible`} className="mr-2">
                {t`Show on Printable Schedule`}
            </Form.Label>
            <Form.Check custom
                className="mr-2"
                id={`${id}-visible`}
                checked={block.visible}
                onChange={(e: ChangeEvent) => updateBlock({...block, visible: (e.currentTarget as HTMLInputElement).checked})}
            />
        </Form>
    </div>
}

function blocksReducer(teamCount: number, perTeam: number) {
    return function (blocks: ScheduleBlock[], action: {
            replace?: ScheduleBlock,
            insert?: ScheduleBlock,
            lastPlayed?: number
        }): ScheduleBlock[] {
        const ret = blocks.map(b => {
            return action.replace == b ? action.insert : b
        }).filter((b): b is ScheduleBlock => !!b)
        if (!action.replace && action.insert) {
            ret.push(action.insert)
        }
        ret.sort((a, b) => {
            let diff = Temporal.PlainDateTime.compare(a.start, b.start)
            if(diff != 0) return diff;
            if(a.type == "BREAK" && b.type == "MATCH")
            {
                return -1;
            }
            if(a.type == "MATCH" && b.type == "BREAK")
            {
                return 1;
            }
            return 0;
        })
        while (ret.length > 0 && ret[0].type == "BREAK") {
            ret.shift();
        }
        while (ret.length > 0 && ret[ret.length - 1].type == "BREAK") {
            ret.pop();
        }
        // Ensure we can't have blocks that span multiple days
        for (let i = 0; i < ret.length; i++) {
            if(ret[i].start.toPlainDate().toString() != ret[i].end.toPlainDate().toString()) {
                if(ret[i].type == "MATCH") {
                    const oldEnd = ret[i].end;
                    const newEnd = ret[i].start.withPlainTime({ hour: 23, minute: 59 });
                    ret[i].end = newEnd;
                    const newBlock = {
                        type: "MATCH",
                        start: newEnd.add({minutes: 1}),
                        end: oldEnd,
                        cycleTime: (ret[i] as MatchBlock).cycleTime
                    }
                    if(Temporal.Duration.compare(newBlock.start.until(newBlock.end), newBlock.cycleTime) >= 0) {
                        ret.splice(i + 1, 0,)
                    }
                } else {
                    ret.splice(i, 1);
                }
            }
        }
        for (let i = 1; i < ret.length - 1; i++) {
            if (ret[i].type == "BREAK") {
                const prev = ret[i - 1];
                const next = ret[i + 1];
                ret[i].start = prev.end;
                ret[i].end = next.start;
            }
        }
        if (action.lastPlayed && action.lastPlayed > 0) {
            let count = 0;
            for (let i = 0; i < ret.length; i++) {
                const block = ret[i]
                if (block.type == "MATCH") {
                    if (count < action.lastPlayed) {
                        block.readOnly = true
                    }
                    if (count < action.lastPlayed && action.lastPlayed < count + matchesPerBlock(block)) {
                        const newEnd = block.start.add({seconds: (action.lastPlayed - count) * block.cycleTime.total({unit: 'second'})})
                        ret.splice(i + 1, 0, {
                            type: "MATCH",
                            start: newEnd,
                            end: block.end,
                            cycleTime: block.cycleTime
                        })
                        block.end = newEnd
                        i++;
                    }
                    count += matchesPerBlock(block)
                }
            }
        }
        let count = 0;
        for (let i = 0; i < ret.length; i++) {
            const block = ret[i]
            if (block.type == "MATCH") {
                count += matchesPerBlock(block)
                let surrogates = 0;
                // This assumes surrogates happen in the first "full" match of the round, which empirically
                // appears to be the matchmaker behavior but does not appear documented anywhere
                if(count > Math.ceil(teamCount * 2 / 4)) {
                    surrogates = (4 - (perTeam * teamCount) % 4) % 4
                }
                const teamPlayed = count * 4 - surrogates
                const completeRounds = Math.floor(teamPlayed / teamCount)
                const teamsInNextRound = teamPlayed - teamCount * completeRounds
                const teamsInThisRound = teamCount - teamsInNextRound
                let message;
                if(teamsInNextRound > 0) {
                    message = ngettext(msgid`After this block, ${teamsInNextRound} team will have played ${completeRounds + 1} matches.`, msgid`After this block, ${teamsInNextRound} teams will have played ${completeRounds + 1} matches.`, teamsInNextRound)

                    if(completeRounds != 1) {
                        message += " " + ngettext(msgid`${teamsInThisRound} team will have played ${completeRounds} matches.`, msgid`${teamsInThisRound} teams will have played ${completeRounds} matches.`, teamsInThisRound)
                    } else {
                        message += " " + ngettext(msgid`${teamsInThisRound} team will have played ${completeRounds} match.`, msgid`${teamsInThisRound} teams will have played ${completeRounds} match.`, teamsInThisRound)
                    }
                } else {
                    message = ngettext(msgid`After this block, all teams will have played ${completeRounds} match.`, msgid`After this block, all teams will have played ${completeRounds} matches.`, completeRounds)
                }
                if(surrogates > 0) {
                    message += " " + ngettext(msgid`(And ${surrogates} team will have played as a surrogate.)`, msgid`(And ${surrogates} teams will have played as a surrogate.)`, surrogates)
                }
                block.roundInfo = message
            }

            if(isMatchBlock(block) && i < ret.length - 1 && isMatchBlock(ret[i + 1]) && block.start.toPlainDate().toString() == ret[i + 1].start.toPlainDate().toString()) {
                ret.splice(i + 1, 0, {
                    type: "BREAK",
                    label: "",
                    start: block.end,
                    end: ret[i + 1].start,
                    visible: false
                })
            }
        }
        return ret;
    }
}

function isMatchBlock(b: ScheduleBlock): b is MatchBlock {
    return b.type == "MATCH"
}

export default function MatchSchedule({eventCode, matchCountData, initialSchedule, allowCustomSchedules, startDate, endDate, phase}:
    {eventCode: string, matchCountData: MatchCountData, initialSchedule: ScheduleBlock[], allowCustomSchedules: boolean, startDate: Temporal.PlainDate, endDate: Temporal.PlainDate, phase: 'PRACTICE' | 'QUALS'}) {
    const [perTeam, setPerTeam] = useState(matchCountData.perTeam);
    const matchCount = Math.ceil(matchCountData.teamCount * perTeam / 4);
    const blocksReducerFunc = useCallback(blocksReducer(matchCountData.teamCount, perTeam), [matchCountData.teamCount, perTeam]);
    const [blocks, updateBlocks] = useReducer(blocksReducerFunc, initialSchedule)
    const dateSet = new Set([startDate.toString()])
    for(let d= startDate; d.until(endDate).total({ unit: 'day' }) >= 0; d = d.add({days: 1})) {
        dateSet.add(d.toString())
    }
    // In case the event dates are changed ensure existing blocks render
    blocks.forEach(b => {
        dateSet.add(b.start.toPlainDate().toString());
    })
    const dates = [...dateSet].map(d => Temporal.PlainDate.from(d));
    dates.sort(Temporal.PlainDate.compare);
    const [scheduleHtml, setScheduleHtml] = useState<string | undefined>(undefined);
    const [active, setActive] = useState(false);
    const [lastPlayed, setLastPlayed] = useState(-1);
    const [hasSchedule, setHasSchedule] = useState(false);
    const [scheduleHeight, setScheduleHeight] = useState("0");
    const scheduleRef = useRef<HTMLIFrameElement>(null);
    const [lastMMUpdates, setLastMMUpdates] = useState<Record<string, MatchMakerUpdate>>({});
    const [currentFile, setCurrentFile] = useState<File | null>(null);
    usePersistentWebsocket((window.location.protocol.indexOf('s') > 0 ? "wss://" : "ws://") + window.location.host + `/stream/matchmaker/?code=${eventCode}`, async (evt: Record<string, MatchMakerUpdate>) => {
        setLastMMUpdates(evt);
        if(evt[phase]?.status === 'SUCCESS') {
            loadData()
        }
    })
    const lastMMUpdate = lastMMUpdates[phase]?.status === 'SUCCESS' ? undefined : lastMMUpdates[phase];

    const minCycle = matchCountData.teamCount > 11 ? 4 : (matchCountData.teamCount > 7 ? 8 : 9);

    useEffect(() => {
        if(blocks.length == 0 && dates.length >= 1) {
            const cycleTime = Math.max(7, minCycle);
            // prefer a weekend for quals
            const preferredDate = dates.filter(d => phase == 'QUALS' ? d.dayOfWeek >= 6 : true)[0] || dates[0]
            const start = preferredDate.toPlainDateTime(new Temporal.PlainTime(8, 0))
            const end = start.add(Temporal.Duration.from({ minutes: matchCount * cycleTime })).round({smallestUnit: "minutes", roundingMode: "expand", roundingIncrement: 5});
            updateBlocks({ insert: { type: "MATCH", cycleTime: Temporal.Duration.from({ minutes: cycleTime }), start, end } })
        }
    }, [matchCountData])

    async function loadData() {
        const res = await fetch(`/event/${eventCode}/dashboard/schedule/${phase}/data/`)
        if(res.ok) {
            const data: ScheduleData = await res.json();
            setScheduleHtml(data.schedule)
            setHasSchedule(true)
            setActive(data.scheduleActive)
            setLastPlayed(data.lastPlayed)
        }
    }


    useEffect(() => {
        updateBlocks({ lastPlayed: lastPlayed })
    }, [lastPlayed]);

    useEffect(() => {
        loadData()
    }, []);

    const blocksByDate = blocks.reduce<Record<string, ScheduleBlock[]>>((acc, b: ScheduleBlock) => {
        const date = b.start.toPlainDate().toString()
        acc[date] = acc[date] || []
        acc[date].push(b)
        return acc
    }, {})

    const totalMatchesScheduled = blocks.filter(isMatchBlock).reduce((acc, b) => {
        return acc + matchesPerBlock(b)
    }, 0)

    async function previewSchedule() {
        const res = await fetch(`./preview/`, {
          method: "POST",
          body: PermissiveURLSearchParams({
              mpt: perTeam,
              schedule: JSON.stringify(blocks.map(b => {
                  return {...b, start: b.start.toString(), end: b.end.toString()}
              }))
          })
        })
        if(res.ok) {
            setScheduleHtml(await res.text())
        }
    }

    async function saveSchedule() {
        const res = await fetch(`.`, {
            method: "POST",
            body: PermissiveURLSearchParams({
                mpt: perTeam,
                schedule: JSON.stringify(blocks.map(b => {
                    return {...b, start: b.start.toString(), end: b.end.toString()}
                }))
            })
        })
        if(res.ok) {
            loadData()
        } else if(res.status == 409 || res.status == 400) {
            messageDialog({label: "Failed to save schedule", text: await res.text()})
        } else {
            messageDialog({label: "Failed to save schedule", text: "An unknown error occurred"})
        }
    }

    async function runMatchMaker() {
        const res = await fetch(`./runmatchmaker/`, {
            method: "POST",
            body: PermissiveURLSearchParams({
                mpt: perTeam,
                schedule: JSON.stringify(blocks.map(b => {
                    return {...b, start: b.start.toString(), end: b.end.toString()}
                })),
                rerun: true
            })
        })
        if(!res.ok) {
            if(res.status == 400) {
                messageDialog({label: "Failed to run matchmaker", text: await res.text()})
            } else {
                messageDialog({ label: "Failed to run matchmaker", text: "An unknown error occurred" })
            }
        }
    }

    function clearMatches() {
        confirmDialog({
            label: t`Clear Matches`,
            text: t`Are you sure you want to clear all matches? This action cannot be undone.`,
            buttonText: t`Clear Matches`,
            onConfirm: async () => {
                const res = await fetch(`./clearmatches/`, {
                    method: "POST"
                })
                if(res.ok) {
                    setScheduleHtml(undefined)
                    setHasSchedule(false)
                    setActive(false)
                    setLastPlayed(-1)
                }
            }
        })
    }

    async function toggleActive() {
        if (active) {
            if (!await confirmDialog({
                label: t`Deactivate Schedule`,
                buttonText: t`Deactivate`,
                text: '<div className="alert alert-danger" role="alert">' +
                    '<i className="fa fa-exclamation-triangle"></i>' +
                    t`DO NOT deactivate the schedule unless it was activated in error.  The match schedule has already been activated and is public, and you will not be able to play matches with a deactivated schedule.` +
                    '<i className="fa fa-exclamation-triangle"></i></div>'
            })) {
                return;
            }
        }
        const res = await fetch('./active/', {
            method: 'POST',
            body: active ? 'false' : 'true',
            credentials: 'same-origin'
        })
        if(res.ok) {
            setActive(!active)
        }
    }

    async function uploadSchedule() {
        if(!currentFile) {
            return;
        }

        if (hasSchedule) {
            if(!await confirmDialog({
                label: t`Overwrite Schedule`,
                text: t`A match schedule already exists for this event. Are you sure you want to import? This will overwrite the current schedule.`
            })) {
                return;
            }
            await fetch(`./clearmatches/`, {
                method: "POST"
            })
            setScheduleHtml(undefined)
            setHasSchedule(false)
            setActive(false)
            setLastPlayed(-1)
        }


        const formData = new FormData();
        formData.append("file", currentFile, currentFile.name);
        const res = await fetch(`./import/`, {
            method: "POST",
            body: formData
        })

        if(res.ok) {
            // Since the import may have changed the blocks and not just the schedule itself, just reload to make sure
            // the state is correct
            window.location.reload()
        } else {
            const text = await res.text();
            messageDialog({label: "Failed to import schedule", text, dangerous: true})
        }
    }

    const wrongMatchCount = totalMatchesScheduled != matchCount;
    const anyOverlaps = Object.values(blocksByDate).some((blocks) => {
        const matchBlocks = blocks.filter(isMatchBlock)
        for(let i = 1; i < matchBlocks.length; i++) {
            if(Temporal.PlainDateTime.compare(matchBlocks[i].start, matchBlocks[i-1].end) < 0) {
                return true;
            }
        }
        return false;
    })
    const conflict = wrongMatchCount || anyOverlaps;
    const phaseString = phase == 'PRACTICE' ? t`practice` : t`qualification`

    return <>
        <h1 className={"text-center"}>{phase == 'PRACTICE' ? t`Practice Match Schedule` : t`Qualfication Match Schedule`}</h1>
        {phase == 'PRACTICE' ? <Alert variant={"warning"} className={"text-center"}>
            <i className="fa fa-exclamation-triangle text-center"></i>&nbsp;
            {t`WARNING: This is the practice match schedule, not the qualification match schedule!`}&nbsp;
            <i className="fa fa-exclamation-triangle text-center"></i>
        </Alert> : null}
        <div className={"row"}>
            <div className={"col-4"}>
                <label>{t`Matches per Team:`}&nbsp;</label>
                <FriendlyNumberInput value={perTeam} onChange={(val) => setPerTeam(val)}
                                     min={matchCountData.minPerTeam} max={matchCountData.maxPerTeam}  />
            </div>
            <span className={"col-4"}>{t`Teams:`} {matchCountData.teamCount}</span>
            <span className={"col-4"}>{t`Total Matches Required:`} {matchCount}</span>
            {lastPlayed > 0 ? <span className={"col-4"}>{t`Last Match Started:`} {lastPlayed}</span> : null}
        </div>
        {matchCountData.teamCount <= 7 ? <Alert
            variant={"info"}>{t`With ${matchCountData.teamCount} teams, there must be a break under T206 between every match. Therefore, the minimum match cycle time is 9 minutes.`}</Alert> : null}
        {matchCountData.teamCount > 7 && matchCountData.teamCount <= 11 ? <Alert
            variant={"info"}>{t`With ${matchCountData.teamCount} teams, there must be a break under T206 approximately every other match. Therefore, the average minimum match cycle time is 8 minutes.`}</Alert> : null}
        {dates.map(d => {
            const dayBlocks = blocksByDate[d.toString()] || [];
            const newBlockStartTime = dayBlocks.slice(-1)[0]?.end || d.toPlainDateTime(new Temporal.PlainTime(8, 0))
            const newBlockCycles = dayBlocks.filter(isMatchBlock).slice(-1)[0]?.cycleTime || Temporal.Duration.from({minutes: Math.max(minCycle, 7)})
            const newBlockEndTime = newBlockStartTime.add({seconds: Math.max(0, matchCount - totalMatchesScheduled) * newBlockCycles.total({unit: 'second'})});
            return <div key={d.toString()}>
                <h3>{d.toLocaleString(document.documentElement.lang, {
                    weekday: 'long',
                    month: 'long',
                    day: 'numeric',
                    year: 'numeric'
                })}</h3>
                {dayBlocks.map((b, idx) => {
                    const previousBlock: MatchBlock | undefined = blocksByDate[d.toString()].slice(0, idx).filter(isMatchBlock).slice(-1)[0];
                    const nextBlock: MatchBlock | undefined = blocksByDate[d.toString()].slice(idx + 1).filter(isMatchBlock)[0];
                    return <>
                        {isMatchBlock(b) ?
                            <EditMatchBlock date={d} block={b} updateBlock={(newBlock) => updateBlocks({ replace: b, insert: newBlock })}
                                        minCycle={minCycle}
                                        overlaps={(previousBlock && Temporal.PlainDateTime.compare(previousBlock.end, b.start) > 0) || nextBlock && Temporal.PlainDateTime.compare(b.end, nextBlock.start) > 0}/> :
                            <EditBreakBlock block={b} updateBlock={(newBlock) => updateBlocks({ replace: b, insert: newBlock })}/>}
                    </>
                })}
                <Button variant={"secondary"} size={"sm"} className={"mb-2"} onClick={() => updateBlocks({ insert: {
                    type: "MATCH",
                    cycleTime: newBlockCycles,
                    start: newBlockStartTime,
                    end: newBlockEndTime
                }})}>{t`Add Match Block`}</Button>
            </div>
        })}
        {totalMatchesScheduled != matchCount ? <Alert
            variant={"danger"}>{t`${totalMatchesScheduled} matches scheduled, but ${matchCount} matches required`}</Alert> : null}
        {anyOverlaps ? <Alert
            variant={"danger"}>{t`Overlapping matches scheduled`}</Alert> : null}

        <div>
            <Button variant={"secondary"} onClick={previewSchedule} disabled={conflict}>{t`Preview`}</Button>
            <Button variant={"secondary"} onClick={saveSchedule} className={"ml-2"}
                    disabled={conflict}>{t`Save`}</Button>
            {hasSchedule ?
                <Button variant={"warning"} disabled={lastPlayed > 0} title={lastPlayed > 0 ? t`Cannot clear schedule once matches have been played` : ''} className={"ml-2"} onClick={clearMatches}>{t`Clear Matches`}</Button>
                : <Button variant={"secondary"} id="runMatchmaker" onClick={runMatchMaker} className={"ml-2"} disabled={conflict || (lastMMUpdate && lastMMUpdate.status == MatchMakerStatus.RUNNING)}>{t`Run Matchmaker`}</Button>}
            {hasSchedule ?
                <Button id="activateQualificationSchedule" variant={active ? "warning" : "primary"} className={"ml-2"} onClick={toggleActive} disabled={lastPlayed > 0} title={lastPlayed > 0 ? t`Cannot deactivate schedule once matches have been played` : ''}>
                    {phase == 'QUALS' ? (active ? t`Deactivate Qualification Schedule` : t`Activate Qualification Schedule`) : (active ? t`Deactivate Practice Schedule` : t`Activate Practice Schedule`)}
                </Button>
                : null}
        </div>
        {allowCustomSchedules ? <>
            <div className="row justify-content-center mt-2">
                <div className={"col-12"}>
                    {t`Custom Scheduling:`}
                </div>
                <div className={"col-12"}>
                    <Alert variant={"info"}>
                        {t`The ${phaseString} schedule can be imported from a CSV. It is encouraged to generate a schedule with MatchMaker and then edit the team numbers to ensure the schedule follows the correct format.`}
                    </Alert>
                </div>
                <div className="col-2">
                    <button onClick={() => window.open("export/")} className="btn btn-secondary">
                        Export Schedule
                    </button>
                </div>
                <div className="col-4">
                    <input type="file" accept=".csv" onChange={(e) => setCurrentFile((e.target as HTMLInputElement).files?.[0] || null)}
                  /*onChange="document.getElementById('importScheduleButton').disabled = (this.value.length == 0);$('#filePathDisplay').text(document.getElementById('scheduleFile').files[0].name);"*/></input>
                </div>
                <div className="col-2">
                    <button id="importScheduleButton" onClick={() => uploadSchedule()} className="btn btn-secondary"
                            disabled={!currentFile || lastPlayed > 0} title={lastPlayed > 0 ? t`Cannot import new schedule once matches have been played` : ''}>Import Schedule
                    </button>
                </div>
                <div className="col-4">
                    <div id="importStatus" style={{color: "red"}}></div>
                </div>
            </div>
        </> : null}

        {lastMMUpdate ? <div className={"text-center"}>{lastMMUpdate.status == MatchMakerStatus.FAILED ? lastMMUpdate.data.error : t`MatchMaker running...`}</div> : (hasSchedule ? t`Schedule has been generated, see below.` : null)}
        {lastMMUpdate && lastMMUpdate.status == MatchMakerStatus.RUNNING ? <ProgressBar now={lastMMUpdate.data.progress} label={`${lastMMUpdate.data.progress}%`} /> : null}

        {scheduleHtml ? <div className="col-12">
            <iframe srcDoc={scheduleHtml} width="100%" height={scheduleHeight} ref={scheduleRef} style={{border: "none"}}
                    onLoad={() => setScheduleHeight(scheduleRef.current!.contentWindow!.document.body.scrollHeight + "px")} />
        </div> : null}
    </>
}